import json

# Load the final results from the previous analysis
with open("file_storage/functions.query_db:32.json", 'r') as f:
    children_books = json.load(f)

with open("file_storage/functions.query_db:33.json", 'r') as f:
    reviews_2020 = json.load(f)

# Process the data to find books with average rating >= 4.5
book_dict = {}
for book in children_books:
    book_id = book['book_id']
    book_dict[book_id] = {
        'title': book['title'],
        'author': book['author']
    }

# Calculate average ratings
book_ratings = {}
for review in reviews_2020:
    purchase_id = review['purchase_id']
    # Match bookid_X with purchaseid_X
    book_id = purchase_id.replace('purchaseid_', 'bookid_')
    if book_id in book_dict:
        rating = float(review['rating'])
        if book_id not in book_ratings:
            book_ratings[book_id] = []
        book_ratings[book_id].append(rating)

# Filter books with average rating >= 4.5
results = []
for book_id, ratings in book_ratings.items():
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating >= 4.5:
        book_info = book_dict[book_id]
        author_name = 'Unknown'
        if book_info['author'] != 'None':
            # Extract author name from JSON string
            try:
                author_data = json.loads(book_info['author'].replace("'", "\""))
                if isinstance(author_data, dict) and 'name' in author_data:
                    author_name = author_data['name']
                else:
                    author_name = str(author_data)
            except:
                author_name = str(book_info['author'])

        results.append({
            'title': book_info['title'],
            'author': author_name,
            'average_rating': round(avg_rating, 2),
            'review_count': len(ratings)
        })

# Sort by average rating (descending) and review count (descending)
results = sorted(results, key=lambda x: (-x['average_rating'], -x['review_count']))

print('__RESULT__:')
print(json.dumps(results, indent=2))

