books = json.loads(open('file_storage/functions.query_db:58.json').read())
reviews = json.loads(open('file_storage/functions.query_db:59.json').read())

book_dict = {b['book_id']: b for b in books}
ratings = defaultdict(list)

for r in reviews:
    book_id = r['purchase_id'].replace('purchaseid_', 'bookid_')
    if book_id in book_dict:
        ratings[book_id].append(float(r['rating']))

output = []
for book_id, rating_list in ratings.items():
    avg_rating = sum(rating_list) / len(rating_list)
    if avg_rating >= 4.5:
        book = book_dict[book_id]
        author = book['author']
        if author == 'None' or author is None:
            author_name = 'Unknown'
        elif author.startswith('{'):
            try:
                author_data = json.loads(author.replace("'", '"'))
                author_name = author_data.get('name', 'Unknown')
            except:
                author_name = 'Unknown'
        else:
            author_name = author

        output.append({
            'title': book['title'],
            'author': author_name,
            'avg_rating': round(avg_rating, 2),
            'review_count': len(rating_list)
        })

output.sort(key=lambda x: (-x['avg_rating'], -x['review_count']))

