result_lines = []
result_lines.append('CHILDREN BOOKS WITH RATING >= 4.5 (2020 ONWARDS)')
result_lines.append('=' * 50)
result_lines.append('')

if not output:
    result_lines.append('No books found matching criteria')
else:
    for idx, book in enumerate(output, 1):
        result_lines.append(str(idx) + '. ' + book['title'])
        result_lines.append('   Author: ' + book['author'])
        result_lines.append('   Rating: ' + str(book['avg_rating']) + ' (' + str(book['review_count']) + ' reviews)')
        result_lines.append('')

final_output = '\n'.join(result_lines)

print('__RESULT__:')
print(json.dumps(final_output))

